SELECT ?game ?attendance WHERE {
  ?series wdt:P649 "National League Championship Series" ;
          wdt:P585 ?series_date .
  FILTER (YEAR(?series_date) >= 1970 && YEAR(?series_date) <= 1979)
  ?series wdt:P154 ?game .
  # Check both team orders: Pirates home vs Reds away, or Reds home vs Pirates away
  { ?game wdt:P249 wd:Q1508 ; wdt:P1320 wd:Q2184 }
  UNION
  { ?game wdt:P249 wd:Q2184 ; wdt:P1320 wd:Q1508 }
  ?game wdt:P1337 ?attendance .
} ORDER BY DESC(?attendance) LIMIT 1

SELECT ?game ?attendance WHERE {
  ?game wdt:P62 wd:Q721182 ;  # Competing in National League Championship Series
  wdt:P585 ?date ;
  wdt:P249 wd:Q1508 ;   # Pirates as home team
  wdt:P1320 wd:Q2184 ; # Reds as away team
  wdt:P1337 ?attendance .
  FILTER (YEAR(?date) >= 1970 && YEAR(?date) <= 1979)
  UNION
  ?game wdt:P62 wd:Q721182 ;
  wdt:P585 ?date ;
  wdt:P249 wd:Q2184 ;   # Reds as home team
  wdt:P1320 wd:Q1508 ; # Pirates as away team
  wdt:P1337 ?attendance .
  FILTER (YEAR(?date) >= 1970 && YEAR(?date) <= 1979)
} ORDER BY DESC(?attendance) LIMIT 1

